'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Logo } from '@/components/logo';
import { AlertCircle, Loader2, ShieldCheck, Mail, Lock } from 'lucide-react';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { cn } from '@/lib/utils';
import { motion, AnimatePresence } from 'framer-motion';

export default function LoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const from = searchParams.get('from') || '/portal';
  const verified = searchParams.get('verified') === 'true';
  const isAdminLogin = from.startsWith('/admin');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || 'Something went wrong');
      }

      router.push(from);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 py-12 overflow-hidden bg-[#f8fafc]">
      {/* Decorative Glow */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-4xl h-[600px] bg-brand/5 blur-[120px] rounded-full pointer-events-none" />

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="w-full max-w-md z-10"
      >
        <Card className="glass-card overflow-hidden border-white/40">
          <CardHeader className="text-center pb-2">
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ delay: 0.2 }}
            >
              <Logo className="justify-center mb-8" />
            </motion.div>
            
            <div className="space-y-1">
              <CardTitle className="text-3xl font-black text-brand-dark tracking-tight uppercase">
                {isAdminLogin ? 'Admin Console' : 'Secure Portal'}
              </CardTitle>
              <CardDescription className="font-bold text-muted-foreground uppercase text-[10px] tracking-widest">
                {isAdminLogin 
                  ? 'Infrastructure Management Access' 
                  : 'Enterprise Resource Management'}
              </CardDescription>
            </div>

            {isAdminLogin && (
              <div className="mt-4 flex items-center justify-center gap-2 px-4 py-1.5 rounded-full bg-brand/10 text-brand border border-brand/20 w-fit mx-auto">
                <ShieldCheck className="h-3.5 w-3.5 animate-pulse" />
                <span className="text-[9px] font-black uppercase tracking-[0.2em]">Authorized Access Only</span>
              </div>
            )}
          </CardHeader>

          <CardContent className="pt-8">
            <AnimatePresence mode="wait">
              {error && (
                <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }}>
                  <Alert variant="destructive" className="mb-6 border-destructive/20 bg-destructive/5 rounded-2xl">
                    <AlertCircle className="h-4 w-4" />
                    <AlertDescription className="font-bold text-xs">{error}</AlertDescription>
                  </Alert>
                </motion.div>
              )}
            </AnimatePresence>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-2">
                <Label className="text-[10px] font-black uppercase tracking-widest text-brand-dark ml-1">Identity Email</Label>
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-brand" />
                  <Input
                    type="email"
                    placeholder="name@company.com"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    disabled={isLoading}
                    className="h-14 bg-brand/5 border-brand/10 pl-11 rounded-2xl focus:bg-white transition-all font-medium text-brand-dark placeholder:text-muted-foreground"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between ml-1">
                  <Label className="text-[10px] font-black uppercase tracking-widest text-brand-dark">Security Key</Label>
                  <Link href="/forgot-password" size="sm" className="text-[9px] font-black uppercase text-brand hover:underline">
                    Forgot Key?
                  </Link>
                </div>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-brand" />
                  <Input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required 
                    disabled={isLoading}
                    className="h-14 bg-brand/5 border-brand/10 pl-11 rounded-2xl focus:bg-white transition-all font-medium text-brand-dark"
                  />
                </div>
              </div>
              <Button type="submit" className="w-full h-14 bg-brand hover:bg-brand/90 text-white font-black uppercase tracking-widest shadow-lg shadow-brand/20 rounded-2xl transition-all active:scale-[0.98]" disabled={isLoading}>
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                    Authenticating...
                  </>
                ) : (
                  isAdminLogin ? 'Unlock Console' : 'Sign In to Portal'
                )}
              </Button>
            </form>

            <div className="mt-10 pt-6 border-t border-brand/10 text-center text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
              Need access?{' '}
              <Link href="/register" className="font-black text-brand hover:underline">
                Request Invitation
              </Link>
            </div>
          </CardContent>
        </Card>
      </motion.div>
    </div>
  );
}
